import json

# Get the Europe metadata
europe_result = var_functions.query_db:2

# Check if it's a file path or direct data
if isinstance(europe_result, str) and '.json' in europe_result:
    with open(europe_result, 'r') as f:
        europe_metadata = json.load(f)
else:
    europe_metadata = europe_result

# Extract article IDs and publication dates
article_data = []
for rec in europe_metadata:
    article_data.append({
        'article_id': int(rec['article_id']),
        'publication_date': rec['publication_date']
    })

print('__RESULT__:')
print(json.dumps({
    'total_records': len(article_data),
    'sample': article_data[:5]
}))

