import json

# Load Europe metadata
europe_metadata = json.loads(open('file_storage/functions.query_db:2.json').read())

# Create year-based article IDs and counts
yearly_article_ids = {}
for rec in europe_metadata:
    year = int(rec['publication_date'][:4])
    if year not in yearly_article_ids:
        yearly_article_ids[year] = []
    yearly_article_ids[year].append(rec['article_id'])

# Count articles per year
yearly_counts = {year: len(ids) for year, ids in yearly_article_ids.items()}

# Sort years and show stats
sorted_years = sorted(yearly_counts.items())
print('__RESULT__:')
print(json.dumps({
    'yearly_counts': sorted_years,
    'total_years': len(sorted_years),
    'total_articles': sum(yearly_counts.values())
}))

