import json

# Load Europe metadata
europe_metadata = json.loads(open('file_storage/functions.query_db:2.json').read())

# Extract all article IDs and group by year
yearly_article_ids = {}
for rec in europe_metadata:
    year = int(rec['publication_date'][:4])
    if year not in yearly_article_ids:
        yearly_article_ids[year] = []
    yearly_article_ids[year].append(rec['article_id'])

# Process in batches due to query limitations
all_europe_articles = []
article_id_to_year = {}

for year, ids in yearly_article_ids.items():
    for article_id in ids:
        article_id_to_year[article_id] = year

# Take a sample for classification
sample_ids = list(article_id_to_year.keys())[:200]
print('__RESULT__:')
print(json.dumps({
    'sample_ids': sample_ids[:10],
    'total_ids': len(article_id_to_year),
    'id_to_year_sample': {k: article_id_to_year[k] for k in list(article_id_to_year.keys())[:5]}
}))

